// ============ 工具函数 ============

/**
 * 根据MBTI类型代码获取深度报告
 * @param {string} type - MBTI类型代码，如 'INTJ'
 * @returns {object|null} 该类型的完整报告对象
 */
export function getMBTIReport(type) {
  const key = type.toUpperCase();
  return MBTI_REPORTS[key] || null;
}

/**
 * 获取认知功能栈解释
 * @param {string} type - MBTI类型代码
 * @returns {object|null} 认知功能栈对象
 */
export function getCognitiveStack(type) {
  const key = type.toUpperCase();
  return COGNITIVE_STACKS[key] || null;
}

/**
 * 获取类型的核心摘要（用于列表展示）
 * @param {string} type - MBTI类型代码
 * @returns {object|null} 简化信息对象
 */
export function getTypeSummary(type) {
  const key = type.toUpperCase();
  const meta = MBTI_TYPES[key];
  if (!meta) return null;
  return {
    type: key,
    name: meta.name,
    fullName: meta.fullName,
    icon: meta.icon,
    category: meta.category,
    tagline: meta.tagline,
    oneLiner: meta.oneLiner,
  };
}

/**
 * 获取所有类型的摘要列表
 * @returns {object[]} 所有类型摘要的数组
 */
export function getAllTypeSummaries() {
  return Object.entries(MBTI_TYPES).map(([key, meta]) => ({
    type: key,
    name: meta.name,
    fullName: meta.fullName,
    icon: meta.icon,
    category: meta.category,
    temperament: meta.temperament,
    color: meta.color,
    tagline: meta.tagline,
    oneLiner: meta.oneLiner,
  }));
}

/**
 * 按分类获取类型列表
 * @param {string} category - 分类名
 * @returns {object[]} 该分类下所有类型
 */
export function getTypesByCategory(category) {
  return getAllTypeSummaries().filter(t => t.category === category);
}
